import {
  Directive,
  TemplateRef,
  ViewContainerRef,
  inject,
  ElementRef,
  Renderer2,
  input,
  effect,
} from '@angular/core';
import { PermissionService } from '../../core/services/permission.service';
import { PermissionExpression } from '../../core/models/permission.model';

@Directive({
  selector: '[appPermission]',
})
export class PermissionDirective {
  readonly expression = input<PermissionExpression | null>(null, {
    alias: 'appPermission',
  });
  readonly strategy = input<'hide' | 'disable'>('hide', {
    alias: 'appPermissionStrategy',
  });

  private readonly permissionService = inject(PermissionService);
  private readonly templateRef = inject(TemplateRef, { optional: true });
  private readonly viewContainer = inject(ViewContainerRef);
  private readonly el = inject(ElementRef);
  private readonly renderer = inject(Renderer2);

  private hasView = false;

  constructor() {
    effect(() => {
      this.updateView();
    });
  }

  private updateView(): void {
    const isAllowed = this.permissionService.canAccess(this.expression() ?? '');

    if (this.templateRef) {
      // Structural Directive behavior
      this.handleStructural(isAllowed);
    } else {
      // Attribute Directive behavior
      this.handleAttribute(isAllowed);
    }
  }

  private handleStructural(isAllowed: boolean): void {
    if (!isAllowed) {
      this.hideStructuralView();
      return;
    }
    this.showStructuralView();
  }

  private showStructuralView(): void {
    if (!this.hasView && this.templateRef) {
      this.viewContainer.createEmbeddedView(this.templateRef);
      this.hasView = true;
    }
  }

  private hideStructuralView(): void {
    if (this.hasView) {
      this.viewContainer.clear();
      this.hasView = false;
    }
  }

  private handleAttribute(isAllowed: boolean): void {
    if (this.strategy() === 'disable') {
      this.handleDisableStrategy(isAllowed);
      return;
    }
    this.handleHideStrategy(isAllowed);
  }

  private handleDisableStrategy(isAllowed: boolean): void {
    if (!isAllowed) {
      this.disableElement();
      return;
    }
    this.enableElement();
  }

  private handleHideStrategy(isAllowed: boolean): void {
    if (!isAllowed) {
      this.hideElement();
      return;
    }
    this.showElement();
  }

  private enableElement(): void {
    this.renderer.removeAttribute(this.el.nativeElement, 'disabled');
    this.renderer.removeClass(this.el.nativeElement, 'permission-disabled');
    this.renderer.removeStyle(this.el.nativeElement, 'pointer-events');
    this.renderer.removeStyle(this.el.nativeElement, 'opacity');
  }

  private disableElement(): void {
    this.renderer.setAttribute(this.el.nativeElement, 'disabled', 'true');
    this.renderer.addClass(this.el.nativeElement, 'permission-disabled');
    this.renderer.setStyle(this.el.nativeElement, 'pointer-events', 'none');
    this.renderer.setStyle(this.el.nativeElement, 'opacity', '0.5');
  }

  private showElement(): void {
    this.renderer.removeStyle(this.el.nativeElement, 'display');
  }

  private hideElement(): void {
    this.renderer.setStyle(this.el.nativeElement, 'display', 'none');
  }
}
